mapper.select:
SELECT u.*, auth.auth, ua.full_Address, r.user_id AS referrer_id FROM ( /* 1. 실제 유저 리스트만 먼저 페이징하여 추출 */ SELECT id, user_id, user_nm, email, phone_num, address_id, point_id, referrer_no, guard_type, role, is_stopped, created_at, (CASE WHEN guard_type = '00' THEN '스텝' WHEN guard_type = '01' THEN '경호원 신청 중' WHEN guard_type = '02' THEN '경호원' WHEN guard_type = '03' THEN '수행' WHEN guard_type = '04' THEN '인솔자' ELSE null END) AS guard_type_nm FROM user WHERE is_Deleted = 'N' AND role != 'Admin'
AND (
(user_id LIKE CONCAT('%', #{option.keyword}, '%') OR user_nm LIKE CONCAT('%', #{option.keyword}, '%') OR email LIKE CONCAT('%', #{option.keyword}, '%') OR nickname LIKE CONCAT('%', #{option.keyword}, '%') OR phone_num LIKE CONCAT('%', #{option.keyword}, '%'))
user_id LIKE CONCAT('%', #{option.keyword}, '%') user_nm LIKE CONCAT('%', #{option.keyword}, '%') email LIKE CONCAT('%', #{option.keyword}, '%') nickname LIKE CONCAT('%', #{option.keyword}, '%') phone_num LIKE CONCAT('%', #{option.keyword}, '%') role LIKE CONCAT('%', #{option.keyword}, '%') is_stopped LIKE CONCAT('%', #{option.keyword}, '%')
)
ORDER BY point_id DESC, id DESC ORDER BY (referrer_no IS NULL) ASC, created_at DESC ORDER BY (guard_type IS NULL) ASC, created_at DESC ORDER BY id DESC
/* 2. 페이징 처리 (이 부분이 추가되어야 합니다) */
) u /* 3. 페이징된 유저에 대해서만 상세 정보 조인 */ LEFT OUTER JOIN user_address ua ON u.address_id = ua.address_id LEFT OUTER JOIN user_auth auth ON u.id = auth.no LEFT OUTER JOIN user r ON u.referrer_no = r.id

